// Create a logo in the top-left corner
ScreenImageMgr.createScreenImage("logo", "logo.png", 10, 10, 1.0, true, 1.0);

// Create a semi-transparent watermark in the bottom-right corner
var screenWidth = core.getScreenWidth();
var screenHeight = core.getScreenHeight();
ScreenImageMgr.createScreenImage("watermark", "watermark.png", screenWidth - 200, screenHeight - 100, 0.8, true, 0.5, 2.0);

// Create an invisible image that will fade in later
ScreenImageMgr.createScreenImage("hidden", "overlay.png", 100, 100, 1.0, false, 1.0, 0.5);

// Later, show it (will fade in over 0.5 seconds)
ScreenImageMgr.showImage("hidden", true);

// Create a background image that covers the whole screen
ScreenImageMgr.createScreenImage("bg", "background.jpg", 0, 0, 1.0, true, 1.0);
var bgWidth = ScreenImageMgr.getImageWidth("bg");
var bgHeight = ScreenImageMgr.getImageHeight("bg");
if(bgWidth < screenWidth || bgHeight < screenHeight) {
    // Scale to cover screen
    var scaleX = screenWidth / bgWidth;
    var scaleY = screenHeight / bgHeight;
    var scale = Math.max(scaleX, scaleY);
    ScreenImageMgr.setImageScale("bg", scale, scale, 0);
}

if(ScreenImageMgr.getShowImage("logo")) {
    core.debug("Logo is visible");
} else {
    core.debug("Logo is hidden or does not exist");
    ScreenImageMgr.showImage("logo", true);
}

// Hide the logo
ScreenImageMgr.showImage("logo", false);

// Wait 2 seconds, then show it again (fades in)
core.wait(2);
ScreenImageMgr.showImage("logo", true);

