var width = ScreenImageMgr.getImageWidth("logo");
core.debug("Logo width: " + width + " pixels");

// Center an image on screen
function centerImage(id) {
    var screenW = core.getScreenWidth();
    var screenH = core.getScreenHeight();
    var imgW = ScreenImageMgr.getImageWidth(id);
    var imgH = ScreenImageMgr.getImageHeight(id);
    ScreenImageMgr.setImageXY(id, (screenW - imgW) / 2, (screenH - imgH) / 2, 0);
}
centerImage("logo");

var scaleX = ScreenImageMgr.getImageScaleX("logo");
core.debug("Horizontal scale: " + scaleX);

// Check if image is currently stretched
var scaleY = ScreenImageMgr.getImageScaleY("logo");
if(Math.abs(scaleX - scaleY) > 0.01) {
    core.debug("Image is non-uniformly scaled");
}

// Zoom in slowly over 2 seconds
ScreenImageMgr.setImageScale("logo", 2.0, 2.0, 2.0);

// Shrink instantly
ScreenImageMgr.setImageScale("logo", 0.5, 0.5, 0);

// Stretch horizontally only (widescreen effect)
ScreenImageMgr.setImageScale("logo", 3.0, 1.0, 1.5);

// Create a pulsing effect
function pulseImage(id, cycles) {
    for(var i=0; i<cycles; i++) {
        ScreenImageMgr.setImageScale(id, 1.2, 1.2, 0.3);
        core.wait(0.3);
        ScreenImageMgr.setImageScale(id, 1.0, 1.0, 0.3);
        core.wait(0.3);
    }
}
pulseImage("logo", 3);

// Zoom and fade out simultaneously
ScreenImageMgr.setImageScale("logo", 3.0, 3.0, 1.5);
ScreenImageMgr.showImage("logo", false);  // will fade out over its fadeDuration

// Make the logo semi-transparent
ScreenImageMgr.setImageAlpha("logo", 0.6);

// Make it fully opaque
ScreenImageMgr.setImageAlpha("logo", 1.0);

// Create a fade-out effect by reducing alpha over time
function fadeOut(id, steps, stepDelay) {
    var alpha = 1.0;
    for(var i=0; i<steps; i++) {
        alpha -= 1.0 / steps;
        ScreenImageMgr.setImageAlpha(id, Math.max(0, alpha));
        core.wait(stepDelay);
    }
    ScreenImageMgr.showImage(id, false);
}
fadeOut("logo", 10, 0.2);

// Create a ghost effect by cycling alpha
function ghostEffect(id, cycles) {
    for(var i=0; i<cycles; i++) {
        ScreenImageMgr.setImageAlpha(id, 0.3);
        core.wait(0.5);
        ScreenImageMgr.setImageAlpha(id, 0.8);
        core.wait(0.5);
    }
}
ghostEffect("logo", 3);

