var imgW = ScreenImageMgr.getImageWidth("logo");
ScreenImageMgr.setImageXY("logo", screenW - imgW - 10, 10, 0);

// Move logo across the screen slowly (slide-in effect)
ScreenImageMgr.setImageXY("logo", 10, 100, 2.0);

// Move to center of screen
function centerImage(id) {
    var screenW = core.getScreenWidth();
    var screenH = core.getScreenHeight();
    var imgW = ScreenImageMgr.getImageWidth(id);
    var imgH = ScreenImageMgr.getImageHeight(id);
    ScreenImageMgr.setImageXY(id, (screenW - imgW) / 2, (screenH - imgH) / 2, 1.0);
}
centerImage("logo");

// Create a slideshow effect (images enter from right)
function slideInFromRight(id, duration) {
    var screenW = core.getScreenWidth();
    var imgW = ScreenImageMgr.getImageWidth(id);
    ScreenImageMgr.setImageXY(id, screenW, 100, 0);  // start off-screen
    ScreenImageMgr.showImage(id, true);
    ScreenImageMgr.setImageXY(id, screenW - imgW - 10, 100, duration);  // slide in
}
slideInFromRight("logo", 1.5);

// Move logo 100 pixels right and 50 pixels down
ScreenImageMgr.addImageXY("logo", 100, 50, 1.0);

