// Simpler bounce
for(var i = 0; i < 3; i++) {
    ScreenImageMgr.addImageXY("logo", 0, -20, 0.2);
    core.wait(0.2);
    ScreenImageMgr.addImageXY("logo", 0, 20, 0.2);
    core.wait(0.2);
}

// Create a wavy motion path
function waveMotion(id, amplitude, duration, cycles) {
    for(var i = 0; i < cycles; i++) {
        ScreenImageMgr.addImageXY(id, 20, 0, duration/4);
        core.wait(duration/4);
        ScreenImageMgr.addImageXY(id, 0, amplitude, duration/4);
        core.wait(duration/4);
        ScreenImageMgr.addImageXY(id, 20, 0, duration/4);
        core.wait(duration/4);
        ScreenImageMgr.addImageXY(id, 0, -amplitude, duration/4);
        core.wait(duration/4);
    }
}
waveMotion("logo", 30, 2.0, 2);

